import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Token-Statistiken: Kostenüberwachung und Datenanalyse | Antigravity Manager","description":"Erfahren Sie, wie Sie die Token-Stats-Funktion verwenden. Erfahren Sie, wie Sie Token-Daten aus Antworten extrahieren, den Verbrauch nach Modell und Konto analysieren, mit Top-Listen die teuersten Modelle und Konten identifizieren und fehlende Statistiken beheben.","frontmatter":{"title":"Token-Statistiken: Kostenüberwachung und Datenanalyse | Antigravity Manager","sidebarTitle":"Auf einen Blick: Wer am teuersten ist","subtitle":"Token-Statistiken: Kostenüberwachung und Datenanalyse","description":"Erfahren Sie, wie Sie die Token-Stats-Funktion verwenden. Erfahren Sie, wie Sie Token-Daten aus Antworten extrahieren, den Verbrauch nach Modell und Konto analysieren, mit Top-Listen die teuersten Modelle und Konten identifizieren und fehlende Statistiken beheben.","tags":["Token Stats","Kosten","Überwachung","SQLite","Verbrauchsstatistik"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"de/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),r={name:"de/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function o(s,e,d,l,u,h){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="token-statistiken-kostenorientierte-statistikdefinitionen-und-diagrammanalyse" tabindex="-1">Token-Statistiken: Kostenorientierte Statistikdefinitionen und Diagrammanalyse <a class="header-anchor" href="#token-statistiken-kostenorientierte-statistikdefinitionen-und-diagrammanalyse" aria-label="Permalink to &quot;Token-Statistiken: Kostenorientierte Statistikdefinitionen und Diagrammanalyse&quot;">​</a></h1><p>Sie haben bereits Ihre Clients an Antigravity Tools angeschlossen, aber &quot;wer verursacht die Kosten, wo ist es teurer geworden und hat plötzlich ein Modell extrem zugelegt&quot; lässt sich schwer intuitiv beurteilen. In diesem Lektion geht es nur um eines: Die Datendefinitionen auf der Token-Stats-Seite zu erklären und Ihnen zu zeigen, wie Sie mit Diagrammen schnell Kostenprobleme lokalisieren.</p><h2 id="was-sie-nach-diesem-lektion-konnen" tabindex="-1">Was Sie nach diesem Lektion können <a class="header-anchor" href="#was-sie-nach-diesem-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Lektion können&quot;">​</a></h2><ul><li>Erklären, woher die Token-Stats-Daten stammen (wann wird aufgezeichnet, in welchen Fällen fehlen Daten)</li><li>Zeitfenster zwischen Stunde/Tag/Woche wechseln, um Fehlentscheidungen durch &quot;nur einen Tag&quot; zu vermeiden</li><li>In den beiden Ansichten &quot;Nach Modell / Nach Konto&quot; mit Trenddiagrammen anomale Spitzenwerte finden</li><li>Mit Top-Listen die teuersten Modelle/Kontos identifizieren und dann im Request-Log nach Ursachen suchen</li></ul><h2 id="ihre-aktuellen-herausforderungen" tabindex="-1">Ihre aktuellen Herausforderungen <a class="header-anchor" href="#ihre-aktuellen-herausforderungen" aria-label="Permalink to &quot;Ihre aktuellen Herausforderungen&quot;">​</a></h2><ul><li>Sie fühlen, dass die Aufrufe teurer geworden sind, wissen aber nicht, ob das Modell geändert wurde, das Konto gewechselt wurde oder an einem Tag plötzlich das Volumen gestiegen ist</li><li>Sie haben <code>X-Mapped-Model</code> gesehen, sind sich aber nicht sicher, nach welchem Modellstandard die Statistik berechnet wird</li><li>Token-Stats zeigt manchmal 0 oder &quot;keine Daten&quot; an, und Sie wissen nicht, ob kein Verkehr oder keine Statistik erfasst wurde</li></ul><h2 id="wann-sie-diese-methode-anwenden" tabindex="-1">Wann Sie diese Methode anwenden <a class="header-anchor" href="#wann-sie-diese-methode-anwenden" aria-label="Permalink to &quot;Wann Sie diese Methode anwenden&quot;">​</a></h2><ul><li>Sie möchten Kosten optimieren: Quantifizieren Sie zuerst &quot;wer am teuersten ist&quot;</li><li>Sie untersuchen plötzliche Rate-Limits/Anomalien: Verwenden Sie Spitzenzeiten für den Abgleich mit Request-Logs</li><li>Sie haben Änderungen am Modell-Routing oder an der Kontingentverwaltung vorgenommen und möchten überprüfen, ob die Kosten wie erwartet gesunken sind</li></ul><h2 id="was-sind-token-stats" tabindex="-1">Was sind Token-Stats? <a class="header-anchor" href="#was-sind-token-stats" aria-label="Permalink to &quot;Was sind Token-Stats?&quot;">​</a></h2><p><strong>Token-Stats</strong> ist die lokale Verbrauchsstatistikseite von Antigravity Tools: Nach der Weiterleitung von Anforderungen versucht der Proxy, die Token-Anzahl aus <code>usage/usageMetadata</code> im Antwort-JSON oder Streaming-Daten zu extrahieren und jede Anforderung nach Konto und Modell in die lokale SQLite (<code>token_stats.db</code>) zu schreiben. In der UI werden die Daten dann nach Zeit/Modell/Konto aggregiert angezeigt.</p><div class="info custom-block"><p class="custom-block-title">Ein häufiger Fehler im Voraus</p><p>Der &quot;Modell&quot;-Standard von Token-Stats stammt aus dem <code>model</code>-Feld Ihrer Anfrage (oder der Pfadanalyse von Gemins <code>/v1beta/models/&lt;model&gt;</code>), nicht gleich dem <code>X-Mapped-Model</code> nach dem Routing.</p></div><h2 id="🎒-vorbereitung-vor-dem-start" tabindex="-1">🎒 Vorbereitung vor dem Start <a class="header-anchor" href="#🎒-vorbereitung-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitung vor dem Start&quot;">​</a></h2><ul><li>Sie haben bereits mindestens einen Proxy-Aufruf erfolgreich ausgeführt (nicht nur beim <code>/healthz</code>-Check stehen geblieben)</li><li>Ihre Upstream-Antwort gibt Token-Verbrauchs-Felder zurück, die analysiert werden können (andernfalls fehlen die Statistiken)</li></ul><div class="tip custom-block"><p class="custom-block-title">Empfohlene Beglektüre</p><p>Wenn Sie Modell-Mapping verwenden, um <code>model</code> an ein anderes physikalisches Modell zu routen, lesen Sie zuerst <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/advanced/model-router/">Modell-Routing: Benutzerdefiniertes Mapping, Wildcard-Priorität und vordefinierte Strategien</a></strong>. Danach wird die &quot;Statistikdefinition&quot; klarer.</p></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Die Datenkette von Token-Stats lässt sich in drei Abschnitte unterteilen:</p><ol><li>Proxy-Middleware versucht, Token-Verbrauch aus der Antwort zu extrahieren (kompatibel mit <code>usage</code>/<code>usageMetadata</code>, Streaming wird ebenfalls analysiert)</li><li>Wenn gleichzeitig <code>account_email + input_tokens + output_tokens</code> verfügbar sind, wird dies in die lokale SQLite geschrieben (<code>token_stats.db</code>)</li><li>UI ruft aggregierte Daten über Tauri <code>invoke(get_token_stats_*)</code> ab und zeigt sie nach Stunde/Tag/Woche an</li></ol><h2 id="mach-es-mit-mir" tabindex="-1">Mach es mit mir <a class="header-anchor" href="#mach-es-mit-mir" aria-label="Permalink to &quot;Mach es mit mir&quot;">​</a></h2><h3 id="schritt-1-bestatigen-sie-zuerst-dass-sie-verkehr-haben" tabindex="-1">Schritt 1: Bestätigen Sie zuerst, dass Sie &quot;Verkehr haben&quot; <a class="header-anchor" href="#schritt-1-bestatigen-sie-zuerst-dass-sie-verkehr-haben" aria-label="Permalink to &quot;Schritt 1: Bestätigen Sie zuerst, dass Sie &quot;Verkehr haben&quot;&quot;">​</a></h3><p><strong>Warum</strong> Token-Stats-Statistiken stammen aus echten Anforderungen. Wenn Sie nur den Proxy gestartet haben, aber nie eine Modell-Anforderung gesendet haben, zeigt die Seite &quot;keine Daten&quot; an.</p><p>Vorgehensweise: Verwenden Sie die Aufrufmethode, die Sie in <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Lokalen Reverse-Proxy starten und ersten Client anschließen</a></strong> bereits erfolgreich validiert haben, und senden Sie 1-2 Anforderungen.</p><p><strong>Was Sie sehen sollten</strong>: Die Token-Stats-Seite ändert sich von &quot;wird geladen/keine Daten&quot; zu Diagrammen oder Listen.</p><h3 id="schritt-2-wahlen-sie-das-richtige-zeitfenster-stunde-tag-woche" tabindex="-1">Schritt 2: Wählen Sie das richtige Zeitfenster (Stunde/Tag/Woche) <a class="header-anchor" href="#schritt-2-wahlen-sie-das-richtige-zeitfenster-stunde-tag-woche" aria-label="Permalink to &quot;Schritt 2: Wählen Sie das richtige Zeitfenster (Stunde/Tag/Woche)&quot;">​</a></h3><p><strong>Warum</strong> Derselben Daten zeigen unter verschiedenen Fenstern völlig unterschiedliche &quot;Spitzenwerte/Trends&quot;. Die drei Fenster in der UI entsprechen auch unterschiedlichen Abrufbereichen:</p><ul><li>Stunde: letzte 24 Stunden</li><li>Tag: letzte 7 Tage</li><li>Woche: letzte 4 Wochen (Trend-Ansicht aggregiert nach letzten 30 Tagen)</li></ul><p><strong>Was Sie sehen sollten</strong>: Nach dem Wechsel ändert sich die Granularität der Trend-Diagramm-X-Achse (Stunde zeigt &quot;Uhrzeit&quot;, Tag zeigt &quot;Monat/Tag&quot;, Woche zeigt &quot;Jahr-W-Nummer&quot;).</p><h3 id="schritt-3-schauen-sie-zuerst-auf-die-gesamtubersicht-um-die-kostengroße-zu-bestimmen" tabindex="-1">Schritt 3: Schauen Sie zuerst auf die Gesamtübersicht, um die &quot;Kostengröße&quot; zu bestimmen <a class="header-anchor" href="#schritt-3-schauen-sie-zuerst-auf-die-gesamtubersicht-um-die-kostengroße-zu-bestimmen" aria-label="Permalink to &quot;Schritt 3: Schauen Sie zuerst auf die Gesamtübersicht, um die &quot;Kostengröße&quot; zu bestimmen&quot;">​</a></h3><p><strong>Warum</strong> Die Übersichtskarten können zuerst 3 Fragen beantworten: Ist das Gesamtvolumen groß, ist das Verhältnis Eingabe/Ausgabe anomal, und sind die beteiligten Konten/Modelle plötzlich gestiegen.</p><p>Konzentrieren Sie sich auf diese Punkte:</p><ul><li>Gesamt-Tokens (<code>total_tokens</code>)</li><li>Eingabe/Ausgabe-Tokens (<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>Anzahl aktiver Konten (<code>unique_accounts</code>)</li><li>Anzahl verwendeter Modelle (UI verwendet direkt die Länge der &quot;Nach-Modell-Statistikliste&quot;)</li></ul><p><strong>Was Sie sehen sollten</strong>: Wenn die &quot;Anzahl aktiver Konten&quot; plötzlich steigt, bedeutet dies meistens, dass Sie kurzzeitig mehr Konten verwendet haben (z. B. Wechsel auf eine Rotationsstrategie).</p><h3 id="schritt-4-verwenden-sie-verwendungstrends-nach-modell-konto-um-anomale-spitzenwerte-zu-erkennen" tabindex="-1">Schritt 4: Verwenden Sie &quot;Verwendungstrends nach Modell/Konto&quot;, um anomale Spitzenwerte zu erkennen <a class="header-anchor" href="#schritt-4-verwenden-sie-verwendungstrends-nach-modell-konto-um-anomale-spitzenwerte-zu-erkennen" aria-label="Permalink to &quot;Schritt 4: Verwenden Sie &quot;Verwendungstrends nach Modell/Konto&quot;, um anomale Spitzenwerte zu erkennen&quot;">​</a></h3><p><strong>Warum</strong> Trenddiagramme sind der beste Einstiegspunkt, um &quot;plötzlich teurer geworden&quot; zu erkennen. Sie müssen die Ursache vorher nicht kennen, sondern zuerst feststellen, &quot;an welchem Tag/welcher Stunde es gespitzt hat&quot;.</p><p>Vorgehensweise:</p><ol><li>Wechseln Sie im oberen rechten Bereich des Trenddiagramms zwischen &quot;Nach Modell / Nach Konto&quot;</li><li>Bewegen Sie die Maus darüber (Tooltip), um Top-Werte zu sehen, und achten Sie zuerst auf &quot;diejenige, die plötzlich auf den ersten Platz gesprungen ist&quot;</li></ol><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Nach Modell: Ein Modell steigt in einem bestimmten Zeitraum plötzlich an</li><li>Nach Konto: Ein Konto steigt in einem bestimmten Zeitraum plötzlich an</li></ul><h3 id="schritt-5-verwenden-sie-top-listen-um-das-teuerste-ziel-festzulegen" tabindex="-1">Schritt 5: Verwenden Sie Top-Listen, um das &quot;teuerste Ziel&quot; festzulegen <a class="header-anchor" href="#schritt-5-verwenden-sie-top-listen-um-das-teuerste-ziel-festzulegen" aria-label="Permalink to &quot;Schritt 5: Verwenden Sie Top-Listen, um das &quot;teuerste Ziel&quot; festzulegen&quot;">​</a></h3><p><strong>Warum</strong> Trenddiagramme zeigen Ihnen &quot;wann anomale Werte auftreten&quot;, Top-Listen zeigen Ihnen &quot;wer am teuersten ist&quot;. Wenn Sie diese beiden kreuzen, können Sie schnell den Fehlerbehebungsbereich eingrenzen.</p><p>Vorgehensweise:</p><ul><li>In der Ansicht &quot;Nach Modell&quot; sehen Sie die Tabelle &quot;Detaillierte Statistik nach Modell&quot; mit <code>total_tokens / request_count / Anteil</code></li><li>In der Ansicht &quot;Nach Konto&quot; sehen Sie die Tabelle &quot;Detaillierte Statistik nach Konto&quot; mit <code>total_tokens / request_count</code></li></ul><p><strong>Was Sie sehen sollten</strong>: Die teuersten Modelle/Kontos stehen vorne, und <code>request_count</code> hilft Ihnen zu unterscheiden, ob &quot;einmal besonders teuer&quot; oder &quot;besonders viele Male&quot;.</p><h3 id="schritt-6-optional-finden-sie-token-stats-db-und-erstellen-sie-eine-sicherung-prufung" tabindex="-1">Schritt 6 (optional): Finden Sie <code>token_stats.db</code> und erstellen Sie eine Sicherung/Prüfung <a class="header-anchor" href="#schritt-6-optional-finden-sie-token-stats-db-und-erstellen-sie-eine-sicherung-prufung" aria-label="Permalink to &quot;Schritt 6 (optional): Finden Sie `token_stats.db` und erstellen Sie eine Sicherung/Prüfung&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie vermuten, dass &quot;Statistiken fehlen&quot; oder eine Offline-Analyse durchführen möchten, ist das direkte Verwenden der SQLite-Datei am zuverlässigsten.</p><p>Vorgehensweise: Gehen Sie in den Advanced-Bereich von Settings, klicken Sie auf &quot;Datadir öffnen&quot;, und Sie finden im Datenverzeichnis <code>token_stats.db</code>.</p><p><strong>Was Sie sehen sollten</strong>: In der Dateiliste ist <code>token_stats.db</code> enthalten (Dateiname ist vom Backend festgeschrieben).</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>Sie können erklären, dass Token-Stats-Statistiken &quot;nach Extraktion aus usage/usageMetadata in Antworten in die lokale SQLite geschrieben werden&quot;, nicht Cloud-Abrechnung</li><li>Sie können in den beiden Trendansichten &quot;Nach Modell / Nach Konto&quot; einen spezifischen Spitzenwert-Zeitraum angeben</li><li>Sie können mit Top-Listen eine ausführbare Fehlerbehebungsentscheidung geben: Welches Modell oder welches Konto zuerst überprüfen</li></ul><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phänomen</th><th>Häufige Ursache</th><th>Was Sie tun können</th></tr></thead><tbody><tr><td>Token-Stats zeigt &quot;keine Daten&quot; an</td><td>Sie haben tatsächlich keine Modell-Anforderungen generiert; oder die Upstream-Antwort enthält keine analysierbaren Token-Felder</td><td>Verwenden Sie zuerst einen bereits validierten Client, um Anforderungen zu senden; prüfen Sie dann, ob die Antwort <code>usage/usageMetadata</code> enthält</td></tr><tr><td>Statistik nach &quot;Modell&quot; sieht falsch aus</td><td>Statistikstandard verwendet <code>model</code> in der Anfrage, nicht <code>X-Mapped-Model</code></td><td>Betrachten Sie Modell-Routing als &quot;Anforderungsmodell -&gt; Mapping-Modell&quot;; Statistik zeigt &quot;Anforderungsmodell&quot;</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Statistiken zu groß nach Aktivierung von Proxy Monitor</td><td>Wenn Proxy Monitor aktiviert ist, werden die Token jeder Anforderung zweimal aufgezeichnet</td><td>Dies ist ein bekanntes Implementierungsdetail, beeinflusst aber die relative Trendanalyse nicht; wenn Sie genaue Werte benötigen, können Sie Monitor vorübergehend deaktivieren und erneut testen</td></tr></tbody></table><h2 id="zusammenfassung-dieses-lektions" tabindex="-1">Zusammenfassung dieses Lektions <a class="header-anchor" href="#zusammenfassung-dieses-lektions" aria-label="Permalink to &quot;Zusammenfassung dieses Lektions&quot;">​</a></h2><ul><li>Der Kernwert von Token-Stats ist &quot;Kostenprobleme zu quantifizieren&quot;, zuerst lokalisieren, dann optimieren</li><li>Beim Schreiben von Statistiken sind Konto und Token-Verbrauch erforderlich; wenn das Modell fehlt, wird es als <code>&quot;unknown&quot;</code> aufgezeichnet (verhindert nicht das Schreiben)</li><li>Wenn Sie eine feinere Kostensteuerung wünschen, führen Sie normalerweise als nächsten Schritt zurück zu Modell-Routing oder Kontingentverwaltung</li></ul><h2 id="vorschau-auf-das-nachste-lektion" tabindex="-1">Vorschau auf das nächste Lektion <a class="header-anchor" href="#vorschau-auf-das-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf das nächste Lektion&quot;">​</a></h2><blockquote><p>Im nächsten Lektion lösen wir das &quot;implizite Stabilitätsproblem in langen Sitzungen&quot;: <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/advanced/context-compression/">Lange Sitzungsstabilität: Kontextkompression, Signatur-Cache und Kompression von Tool-Ergebnissen</a></strong>.</p></blockquote><p>Sie werden lernen:</p><ul><li>Was die drei Schichten der progressiven Kontextkompression jeweils tun</li><li>Warum &quot;Signatur-Cache&quot; 400 Signaturfehler reduzieren kann</li><li>Was bei der Tool-Ergebniskompression gelöscht und was beibehalten wird</li></ul><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Datenbankdateiname und Tabellenstruktur: <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>Schreiblogik: <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>Abfragelogik: Stunde/Tag/Woche, nach Konto/nach Modell, Trend und Übersicht</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Einstellungsseite: Abrufen/Öffnen des Datenverzeichnisses (um <code>token_stats.db</code> zu finden)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const m=t(r,[["render",o]]);export{g as __pageData,m as default};
